return items.map(item => {
  item.json.Amount_clean = parseFloat(
    item.json['Amount'].replace('$', '').replace(/,/g, '')
  );
  return item;
});

// ===============================
// ANALYSE MÉTIER CENTRALISÉE
// ===============================

const caProduit = {};
const caPays = {};
const caVendeur = {};
const caMensuel = {};
const anomalies = [];

// -------------------------------
// 1️⃣ Boucle principale
// -------------------------------

items.forEach(item => {

  const product = item.json.Product;
  const country = item.json.Country;
  const seller = item.json["Sales Person"];
  const amount = item.json.Amount_clean;
  const date = new Date(item.json.Date);

  if (isNaN(date)) return;

  // Mois formaté correctement (YYYY-MM)
  const monthKey =
    date.getFullYear() + "-" + String(date.getMonth() + 1).padStart(2, "0");

  // -------- Détection anomalie --------
  if (amount < 0) {
    anomalies.push({
      type: "Vente négative",
      produit: product,
      montant: amount
    });
  }

  // -------- CA par produit --------
  if (product) {
    caProduit[product] = (caProduit[product] || 0) + amount;
  }

  // -------- CA par pays --------
  if (country) {
    caPays[country] = (caPays[country] || 0) + amount;
  }

  // -------- CA par vendeur --------
  if (seller) {
    caVendeur[seller] = (caVendeur[seller] || 0) + amount;
  }

  // -------- CA mensuel --------
  caMensuel[monthKey] = (caMensuel[monthKey] || 0) + amount;

});

// -------------------------------
// 2️⃣ Produit Top Vente
// -------------------------------

let topProduit = null;
let maxCA = 0;

for (const p in caProduit) {
  if (caProduit[p] > maxCA) {
    maxCA = caProduit[p];
    topProduit = p;
  }
}

// -------------------------------
// 3️⃣ Détection baisse >20%
// -------------------------------

// 🔥 Tri chronologique réel
const mois = Object.keys(caMensuel).sort(
  (a, b) => new Date(a) - new Date(b)
);

const baisse = [];

for (let i = 1; i < mois.length; i++) {

  const prev = caMensuel[mois[i - 1]];
  const current = caMensuel[mois[i]];

  if (prev > 0) {
    const variation = (current - prev) / prev;

    if (variation < -0.2) {
      baisse.push({
        mois: mois[i],
        variation: variation,
        pourcentage: Math.round(variation * 100)
      });
    }
  }
}

// -------------------------------
// 4️⃣ Moyenne mensuelle
// -------------------------------

const totalCA = Object.values(caMensuel).reduce((a, b) => a + b, 0);

const moyenneMensuelle =
  Object.keys(caMensuel).length > 0
    ? totalCA / Object.keys(caMensuel).length
    : 0;


// -------------------------------
// 5️⃣ Indicateur global d’alerte
// -------------------------------

const alerteBaisse = baisse.length > 0;


// ===============================
// 6️⃣ Retour global unique
// ===============================

return [
  {
    json: {
      caProduit,
      caPays,
      caVendeur,
      caMensuel,
      moyenneMensuelle,
      topProduit,
      baisseDetectee: baisse,
      anomalies,
      alerteBaisse   // 👈 prêt pour IF node
    }
  }
];

// Sécurité : vérifier qu'on a bien des données


if (!items.length || !items[0].json) {
  return [];
}

const analysis = items[0].json;

// Sécurisation des objets
const caProduit = analysis.caProduit || {};
const caPays = analysis.caPays || {};
const caMensuel = analysis.caMensuel || {};
const topProduit = analysis.topProduit || null;


// Fonction générique pour créer un graphique


function buildChart(type, labels, values, labelTitle) {
  return {
    type: type,
    data: {
      labels: labels,
      datasets: [
        {
          label: labelTitle,
          data: values
        }
      ]
    }
  };
}


// 1️⃣ Graphique CA par produit


const chartProduit = buildChart(
  "bar",
  Object.keys(caProduit),
  Object.values(caProduit),
  "Chiffre d'affaires par produit"
);


// 2️⃣ Graphique CA par pays


const chartPays = buildChart(
  "pie",
  Object.keys(caPays),
  Object.values(caPays),
  "Chiffre d'affaires par pays"
);


// 3️⃣ Graphique CA mensuel


const chartMensuel = buildChart(
  "line",
  Object.keys(caMensuel),
  Object.values(caMensuel),
  "Chiffre d'affaires mensuel"
);


// 4️⃣ Graphique Top Produit


let chartTopProduit = null;

if (topProduit && caProduit[topProduit]) {
  chartTopProduit = {
    type: "bar",
    data: {
      labels: [topProduit],
      datasets: [
        {
          label: "Top produit",
          data: [caProduit[topProduit]]
        }
      ]
    }
  };
}


// 5️⃣ Fonction génération URL QuickChart


function buildURL(chartConfig) {
  const encoded = encodeURIComponent(JSON.stringify(chartConfig));
  return `https://quickchart.io/chart?width=600&height=400&format=png&c=${encoded}`;
}


// 6️⃣ Retour des graphiques


const results = [
  { json: { type: "Produit", url: buildURL(chartProduit) } },
  { json: { type: "Pays", url: buildURL(chartPays) } },
  { json: { type: "Mensuel", url: buildURL(chartMensuel) } }
];

if (chartTopProduit) {
  results.push({
    json: { type: "TopProduit", url: buildURL(chartTopProduit) }
  });
}

return results;
